    vatLawRows: [['— HVA ER UNNTATT MVA? —','Utenfor loven — ingen mva og ingen fradragsrett'],['Helsetjenester?','Unntatt — lege, tannlege, fysioterapi o.l.','§ 3-2'],['Sosiale tjenester?','Unntatt — barnevern, eldreomsorg, rusomsorg','§ 3-4'],['Undervisning?','Unntatt — skole, kurs, opplæring (offentlig og privat)','§ 3-5'],['Bank, forsikring, verdipapir?','Unntatt — finansielle tjenester','§ 3-6'],['Konsert, teater, dans?','Unntatt — framføring av kunst og kultur','§ 3-7'],['Treningssenter, svømmehall?','Unntatt — rett til å utøve idrett','§ 3-8'],['Offentlig myndighetsutøvelse?','Unntatt','§ 3-9'],['Utleie av eiendom?','Unntatt — men frivillig registrering er mulig for næringseiendom','§ 3-11'],['Veldedige salg (loppemarked o.l.)?','Unntatt','§ 3-12'],['Kontingent i ideelle org.?','Unntatt','§ 3-13'],['Pengespill?','Unntatt','§ 3-14'],['Begravelsesseremoni?','Unntatt','§ 3-15'],['Styrehonorar?','Unntatt mva, men AGA skal betales','§ 3-17'],['Selger du brukte private ting?','Unntatt — privatpersoner beregner ikke mva','§ 3-19'],['— HVA ER FRITATT (0 % MVA)? —','Omfattet av loven, 0 % utg. mva, full fradragsrett'],['Aviser, tidsskrift, bøker?','Fritatt','§ 6-1/6-3/6-4'],['El-kraft til husholdning i Nord-Norge?','Fritatt','§ 6-6'],['Elbil under 300 000 kr?','Fritatt — over dette beregnes 25 % mva','§ 6-8'],['Fartøy over 15 m, luftfartøy i yrke?','Fritatt','§ 6-9/6-10'],['Virksomhetsoverdragelse?','Fritatt — ingen mva når hele virksomheten selges samlet','§ 6-14'],['Eksport av varer og tjenester?','Fritatt — 0 % mva, full fradragsrett på inngående','§ 6-21/6-22'],['Transport til/fra utlandet?','Fritatt','§ 6-28'],['— UTTAK —','Bruker du bedriftens varer eller tjenester privat?'],['Uttak av varer til eget bruk?','Mva-pliktig','§ 3-21'],['Uttak av tjenester privat?','Mva-pliktig','§ 3-22'],['Kost, naturalavlønning, representasjon?','Mva-pliktig','§ 3-23'],['— INNFØRSEL —','Importerer du varer eller tjenester?'],['Varer fra utlandet?','Mva beregnes ved fortolling','§ 3-29'],['Digitale tjenester fra utlandet?','Snudd avregning — du beregner mva selv','§ 3-30']],
    vatDefRows: [['Hva er omsetning?','Levering av varer eller tjenester mot vederlag','§ 1-3 a'],['Hva er varer?','Fysiske gjenstander, fast eiendom, el-kraft, vann, gass, varme, kulde','§ 1-3 b'],['Hva er tjenester?','Alt som kan omsettes og ikke er varer — rådgivning, frisør, transport o.l.','§ 1-3 c'],['Hvem er avgiftssubjekt?','Bedrifter registrert i Mva-registeret (omsetning over 50 000 kr i 12 mnd)','§ 1-3 d'],['Hva er utgående mva?','Mva du legger på prisen og krever inn fra kunden','§ 1-3 e'],['Hva er inngående mva?','Mva du betaler når du kjøper varer/tjenester til bedriften','§ 1-3 f'],['Hva betyr «unntatt»?','Omsetning utenfor loven — ingen mva, men heller ingen fradragsrett','§ 1-3 g'],['Hva betyr «fritatt»?','Omfattet av loven, men 0 % utg. mva — full fradragsrett','§ 1-3 h'],['Fjernleverbare tjenester?','Tjenester ikke knyttet til fysisk sted — IT, rådgivning over nett, streaming','§ 1-3 i'],['Elektroniske tjenester?','Fjernleverbare og automatiserte — apper, e-bøker, strømmetjenester','§ 1-3 j']],
    vatDedRows: [['Kjøper du noe til bedriften?','Du får tilbake inngående mva på alt til bruk i registrert virksomhet','§ 8-1'],['Brukes noe både privat og i bedrift?','Forholdsmessig fradrag etter antatt bruk','§ 8-2'],['Servering til ansatte/kunder?','Aldri fradrag','§ 8-3 a'],['Kundemiddager og representasjon?','Aldri fradrag','§ 8-3 e'],['Gaver over bagatellgrensen?','Aldri fradrag','§ 8-3 f'],['Bolig og velferdstiltak?','Aldri fradrag — unntak for bedriftskantiner','§ 8-3 g'],['Firmabil?','Ingen mva-fradrag — unntak for utleie, taxi og videresalg','§ 8-4'],['Betaling over 10 000 kr?','Må gå via bank for å få mva-fradrag','§ 8-8']],
    vatAdjRows: [['Hva er en kapitalvare (driftsmidler)?','Maskiner, kjøretøy o.l. med inngående mva over 50 000 kr','§ 9-1 a'],['Hva er en kapitalvare (fast eiendom)?','Bygg, anlegg o.l. med inngående mva over 100 000 kr','§ 9-1 b'],['Hvor lenge justeres driftsmidler?','5 år — endrer du bruken må fradraget justeres','§ 9-4'],['Hvor lenge justeres fast eiendom?','10 år — endrer du bruken må fradraget justeres','§ 9-4']],
    vatCalcRows: [['Hva beregnes mva av?','Vederlaget eksklusive mva','§ 4-1'],['Byttehandel?','Markedspris brukes som beregningsgrunnlag','§ 4-3'],['Selger du billig til eget selskap?','Mva beregnes av markedspris ved interessefellesskap','§ 4-4'],['Kunden betaler aldri?','Du kan tilbakeføre mva ved endelig konstatert tap på fordring','§ 4-7']],
    vatRegRows: [['Konsernselskaper som én enhet?','Fellesregistrering ved minst 85 % eierskap — solidaransvar','§ 2-2'],['Leier du ut næringseiendom?','Frivillig registrering gir mva-fradrag på oppussing/bygging','§ 2-3'],['Nyoppstartet med store innkjøp?','Forhåndsregistrering mulig før du har nådd 50 000 kr i omsetning','§ 2-4']],
