    vatHelpRows: [['— SLIK BRUKER DU KALKULATOREN —','Beregn priser med og uten merverdiavgift (MVA)'],['Beløp','Skriv inn beløpet du vil beregne MVA for.'],['MVA-sats','Velg riktig sats: 25% (standard), 15% (mat/drikke), 12% (transport/hotell/kino), eller 0% (fritatt).'],['Beløpet er','Velg om beløpet du skrev inn er med eller uten MVA. «Uten MVA» legger til avgift. «Med MVA» trekker fra avgift.'],['— SLIK LESER DU RESULTATENE —',''],['Pris inkl. MVA','Totalprisen kunden betaler, inkludert avgift.'],['Eks. MVA','Prisen uten avgift — dette er selgerens inntekt.'],['MVA-beløp','Selve avgiften som skal innbetales til staten.'],['Sats %','MVA-satsen som er brukt i beregningen.'],['— GODT Å VITE —',''],['25% er standard','De fleste varer og tjenester har 25% MVA. Mat/drikke har 15%. Transport, hotell og kino har 12%.'],['Eksport er fritatt','Varer og tjenester som eksporteres har 0% MVA, men bedriften beholder fradragsrett.'],['Justeringskalkulatoren','Under MVA-kalkulatoren finner du justeringskalkulatoren for kapitalvarer (mval. kap. 9). Denne beregner justering ved bruksendring.']],
