    adjHelpRows: [['— SLIK BRUKER DU KALKULATOREN —','Beregn justering av inngående MVA ved bruksendring'],['Type kapitalvare','Fast eiendom har 10 års justeringsperiode, maskiner/inventar har 5 år.'],['Total inngående MVA','MVA-beløpet du opprinnelig fikk fradrag for da kapitalvaren ble anskaffet.'],['År brukt','Antall hele år siden MVA-fradraget ble tatt.'],['Gammel andel (%)','Andel avgiftspliktig bruk FØR endringen.'],['Ny andel (%)','Andel avgiftspliktig bruk ETTER endringen.'],['— SLIK LESER DU RESULTATENE —',''],['Tilbakebetaling / økt fradrag','Redusert avgiftspliktig bruk = tilbakebetaling. Økt bruk = du kan kreve mer fradrag.'],['Årlig justering','Beløpet som justeres hvert gjenværende år.'],['Gjenværende år','Antall år igjen av justeringsperioden.'],['— GODT Å VITE —',''],['Terskelverdi','Inngående MVA må overstige 100 000 kr (eiendom) eller 50 000 kr (maskiner) for justeringsplikt.'],['Bruksendring','Typisk: bytte fra avgiftspliktig til fritatt utleie, eller omvendt.']],
